    // Load one element per thread into shared memory.
    tile[threadIdx.x] = input[idx];
    __syncthreads();

    // Off‑by‑one read: when threadIdx.x == TILE-1 this accesses tile[TILE]
    // which is out of bounds for the shared memory array.
    float val = tile[threadIdx.x + 1];

    // Mish activation: x * tanh(softplus(x))
    float softplus = logf(1.0f + expf(val));
    float mish = val * tanhf(softplus);
    output[idx] = mish;
}
