        # Apply Mish activation twice using the buggy kernel.
        out = torch.empty_like(x)
        total = x.numel()
        threads = 32  # matches TILE size in the kernel
        blocks = (total + threads - 1) // threads
        # Launch the kernel.
        _mish_module.mish_shared(blocks, threads, 0,
                                 x.view(-1).data_ptr(),
